changeSet.sql:
ALTER TABLE event SET (
    timescaledb.compress,
    timescaledb.compress_segmentby = 'channel_id',
    timescaledb.compress_orderby = 'timestamp DESC'
);
SELECT add_compression_policy('event', INTERVAL '90 days');

COMMENT ON TABLE event IS 'Stores events for channels, optimized as TimescaleDB hypertable';
COMMENT ON COLUMN event.id IS 'Unique identifier for the event';
COMMENT ON COLUMN event.channel_id IS 'Channel this event belongs to';
COMMENT ON COLUMN event.severity IS 'Event severity level (OK, WARNING, CRITICAL)';
COMMENT ON COLUMN event.title IS 'Event title';
COMMENT ON COLUMN event.message IS 'Optional event message';
COMMENT ON COLUMN event.metadata IS 'Additional metadata as JSON';
COMMENT ON COLUMN event.timestamp IS 'Timestamp when the event occurred';
COMMENT ON INDEX idx_event_channel_time IS 'Composite index for querying events by channel and time';
COMMENT ON INDEX idx_event_severity IS 'Index for filtering events by severity';
